import React, { useEffect, useState } from 'react';
import './Products.css';
import axios from 'axios';
import { Link, useNavigate } from 'react-router-dom';

function Products() {
  const [products, setProducts] = useState([]);
  const [searchQuery, setSearchQuery] = useState("");
  const navigate = useNavigate();

  useEffect(() => {
    axios.get('http://localhost:5000/api/products')
      .then((res) => {
        setProducts(res.data);
      })
      .catch((err) => {
        console.error("Failed to fetch products:", err);
      });
  }, []);

  // 👉 Category filter
  const shirts = products.filter(p => p.category === 'shirt');
  const pants = products.filter(p => p.category === 'pants');
  const innerwears = products.filter(p => p.category === 'innerwear');

  // 👉 Search filter (all products)
  const filterBySearch = (items) =>
    items.filter(item =>
      item.name.toLowerCase().includes(searchQuery.toLowerCase())
    );

  // 👉 Add to Cart handler
  const addToCart = (item) => {
    const token = localStorage.getItem("token");
    if (!token) {
      alert("⚠️ Please Login / Signup before adding to cart");
      navigate("/login");
      return;
    }

    const existingCart = JSON.parse(localStorage.getItem("cart")) || [];

    const newItem = {
      ...item,
      quantity: 1,
      selectedSize: item.sizes ? item.sizes[0] : "Free Size",
    };

    const alreadyInCart = existingCart.find(
      (cartItem) =>
        cartItem._id === newItem._id && cartItem.selectedSize === newItem.selectedSize
    );

    let updatedCart;
    if (alreadyInCart) {
      updatedCart = existingCart.map((cartItem) =>
        cartItem._id === newItem._id && cartItem.selectedSize === newItem.selectedSize
          ? { ...cartItem, quantity: cartItem.quantity + 1 }
          : cartItem
      );
    } else {
      updatedCart = [...existingCart, newItem];
    }

    localStorage.setItem("cart", JSON.stringify(updatedCart));
    alert(`${item.name} added to cart 🛒`);
  };

  return (
    <div className="products-container">

      {/* 🔍 Search bar */}
      <div className="search-bar">
        <input
          type="text"
          placeholder="🔍 Search for products..."
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
        />
      </div>

      {/* Shirts */}
      <h1 className="section-title">🧥 Shirts</h1>
      <div className="product-grid">
        {filterBySearch(shirts).map((item) => (
          <div key={item._id} className="product-card">
            <Link to={`/product/${item._id}`} className="product-card-link">
              <img src={item.image} alt={item.name} />
              <h3>{item.name}</h3>
              <p className="price">₹{item.price}</p>
            </Link>
            <button className="cart-btn" onClick={() => addToCart(item)}>Add to Cart</button>
          </div>
        ))}
      </div>

      {/* Pants */}
      <h1 className="section-title">👖 Pants</h1>
      <div className="product-grid">
        {filterBySearch(pants).map((item) => (
          <div key={item._id} className="product-card">
            <Link to={`/product/${item._id}`} className="product-card-link">
              <img src={item.image} alt={item.name} />
              <h3>{item.name}</h3>
              <p className="price">₹{item.price}</p>
            </Link>
            <button className="cart-btn" onClick={() => addToCart(item)}>Add to Cart</button>
          </div>
        ))}
      </div>

      {/* Innerwear */}
      <h1 className="section-title">🩲 Innerwear</h1>
      <div className="product-grid">
        {filterBySearch(innerwears).map((item) => (
          <div key={item._id} className="product-card">
            <Link to={`/product/${item._id}`} className="product-card-link">
              <img src={item.image} alt={item.name} />
              <h3>{item.name}</h3>
              <p className="price">₹{item.price}</p>
            </Link>
            <button className="cart-btn" onClick={() => addToCart(item)}>Add to Cart</button>
          </div>
        ))}
      </div>

    </div>
  );
}

export default Products;
